12	interface Item {
13	  type: string;
14	}
15	
16	interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	interface Scenario {
22	  customer: { yearsWithMHPCO: number };
23	  steps: QuoteStep[];
24	}
