26	const withFirstInsuranceSurcharge = (base: number): number =>
27	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
28	
29	const itemPremium = (item: Item): number =>
30	  withFirstInsuranceSurcharge(BASE_PREMIUM_BY_TYPE[item.type]);
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const BLOCK_BASE_PREMIUM = 60;
34	const BLOCK_SIZE = 3;
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const sumPremiums = (items: Item[]): number =>
39	  items.reduce((sum, item) => sum + itemPremium(item), 0);
40	
41	const componentsPremium = (components: Item[]): number =>
42	  components.length === BLOCK_SIZE
43	    ? withFirstInsuranceSurcharge(BLOCK_BASE_PREMIUM)
44	    : sumPremiums(components);
45	
46	const sumItemPremiums = (items: Item[]): number =>
47	  componentsPremium(items.filter(isComponent)) +
48	  sumPremiums(items.filter((item) => !isComponent(item)));
49	
50	const quoteStep = ({ items }: QuoteStep) => ({
51	  premium: Math.ceil(sumItemPremiums(items) + PROCESSING_FEE),
52	});
53	
54	export const processScenario = ({ steps }: Scenario): unknown => ({
55	  results: steps.map(quoteStep),
56	});
